<template>
  <div class="container">
    <div class="row">
      <div class="col-md-12">
        <div class="mt-4 mb-4">
          <h1><strong class="courier">scoreboard()</strong></h1>
          <em class="monaco">fast and more.</em>
        </div>
        <div class="card text-white text-left mb-5">
          <div class="maskot">
            <img src="~@/assets/img/maskot.png" class="maskot-img" />
          </div>
          <div class="card-body">
            <!-- <button @click="urutkan" class="btn btn-danger text-white mt-5 mb-3">Urutkan</button> -->
            <div class="table-responsive pt-5">
              <div class="alert alert-info">
                <h3>Keterangan</h3>
                ⚠️ jawaban sedang diuji <br>
                ✅ jawaban benar <br>
                ❌ jawaban salah
              </div>
              <p v-if="contestants.length > 0" class="monaco">
                there are {{ contestants.length }} answers.
              </p>
              <table class="table table-striped text-white">
                <thead>
                  <tr>
                    <th>NAME</th>
                    <th>CLASS</th>
                    <th>TIME</th>
                    <th class="text-center">STATUS</th>
                    <!-- <th>ACTION</th> -->
                  </tr>
                </thead>
                <tbody class="monaco">
                  <tr v-for="c in contestants" :key="c.id" id="data">
                    <td>{{ c.nama }}</td>
                    <td>{{ c.kelas }}</td>
                    <td>{{ c.created_at }}</td>
                    <td class="text-center">
                      <span v-if="c.status == 'benar'">✅</span>  
                      <span v-else-if="c.status == 'salah'">❌</span>  
                      <span v-else>⚠️</span>
                    </td>
                    <!-- <td><button @click="removeTim(t.id)">R</button></td> -->
                  </tr>
                  <tr>
                    <td colspan="4" class="text-center">
                      <em v-if="contestants.length < 1">there is no data.</em>
                    </td>
                  </tr>
                </tbody>
              </table>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  data() {
    return {
      contestants: [],
    };
  },
  async mounted() {
    await this.getData();
  },

  created() {
    this.subsData()
  },

  methods: {
    async getData() {
      const { data, error } = await this.$supabase
        .from('scorePemdas')
        .select('*')
        .order('created_at')
      
      if(error) {
        console.error(error);
        return
      }

      this.setData(data)
    },

    setData(data) {
      this.contestants = data; 
    },

    subsData() {
      const mySubscription = this.$supabase
        .from('score')
        .on('INSERT', (data) => {
          if(data.new) {
            this.contestants.push(data.new)
          }
        })
        .subscribe()
    },
  },
};
</script>

